const express = require('express');
const router = express.Router();

// Middleware to verify object-level authorization
async function authorizeObjectAccess(req, res, next) {
  const userId = req.user.id; // From JWT/session
  const requestedUserId = parseInt(req.params.userId);
  const action = req.method; // GET, PUT, DELETE, etc.

  try {
    // Check 1: User owns the resource
    if (userId === requestedUserId) {
      return next();
    }

    // Check 2: User has delegated access (e.g., admin, shared resource)
    const hasAccess = await checkUserPermissions(userId, requestedUserId, action);

    if (!hasAccess) {
      return res.status(403).json({
        error: 'Forbidden',
        message: 'You do not have permission to access this resource'
      });
    }

    next();
  } catch (error) {
    console.error('Authorization check failed:', error);
    return res.status(500).json({ error: 'Authorization check failed' });
  }
}

// Database query with access control
async function checkUserPermissions(actorId, targetUserId, action) {
  // Example: Check if user is admin
  const actor = await db.users.findById(actorId);
  if (actor.role === 'admin') {
    return true;
  }

  // Example: Check if resource is shared
  const shared = await db.permissions.findOne({
    resource_owner: targetUserId,
    shared_with: actorId,
    permission: action
  });

  return shared !== null;
}

// Protected endpoint with object-level authorization
router.get('/api/users/:userId/profile', 
