  authorizeObjectAccess,     // Step 2: Verify user can access THIS specific object
  async (req, res) => {
    try {
      const user = await db.users.findById(req.params.userId);
      res.json({
        id: user.id,
        email: user.email,
        name: user.name,
        created_at: user.created_at
      });
    } catch (error) {
      res.status(404).json({ error: 'User not found' });
    }
  }
);

// Example for resource-based access (orders, documents, etc.)
router.get('/api/orders/:orderId', 
  authenticateJWT,
  async (req, res) => {
    const userId = req.user.id;
    const orderId = req.params.orderId;

    try {
      // CRITICAL: Query must filter by BOTH orderId AND userId
      const order = await db.orders.findOne({
        id: orderId,
        user_id: userId  // Ensures user can only access their own orders
      });

      if (!order) {
        return res.status(404).json({ error: 'Order not found' });
      }

      res.json(order);
    } catch (error) {
      res.status(500).json({ error: 'Failed to retrieve order' });
    }
  }
);

module.exports = router;

