const express = require('express');
const router = express.Router();

// Generate UUID for new users
router.post('/api/users', async (req, res) => {
  const userId = uuidv4(); // e.g., '9b1deb4d-3b7d-4bad-9bdd-2b0d7b3dcb6d'

  const user = await db.users.create({
    uuid: userId,
    email: req.body.email,
    name: req.body.name
  });

  res.status(201).json({ id: user.uuid, ...user });
});

// Access user by UUID
router.get('/api/users/:userId', 
  authenticateJWT,
  async (req, res) => {
    const requestedUserId = req.params.userId;
    const authenticatedUserId = req.user.id;

    // Validate UUID format to prevent injection
    const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    if (!uuidRegex.test(requestedUserId)) {
      return res.status(400).json({ error: 'Invalid user ID format' });
    }

    // CRITICAL: Still enforce authorization checks!
    if (authenticatedUserId !== requestedUserId && !req.user.isAdmin) {
      return res.status(403).json({ error: 'Forbidden' });
    }

    const user = await db.users.findOne({ uuid: requestedUserId });
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    res.json(user);
  }
);

// Alternative: Cryptographically secure random tokens
function generateSecureToken(length = 32) {
  return crypto.randomBytes(length).toString('base64url');
}

// Use tokens for sensitive resources
router.post('/api/documents', 
  authenticateJWT,
  async (req, res) => {
    const documentToken = generateSecureToken(32);

    const document = await db.documents.create({
      token: documentToken,  // 43 character base64url string
      user_id: req.user.id,
      title: req.body.title,
      content: req.body.content
    });

    // Share document via unguessable URL
    res.status(201).json({
      id: document.token,
      url: `https://api.example.com/api/documents/${document.token}`
    });
  }
);

module.exports = router;

const { AbilityBuilder, Ability } = require('@casl/ability');
const express = require('express');
const router = express.Router();

// Define authorization policies based on user attributes
function defineAbilitiesFor(user) {
  const { can, cannot, build } = new AbilityBuilder(Ability);

  // Public users (not authenticated)
  if (!user) {
    can('read', 'Article', { published: true });
    return build();
  }

  // Regular authenticated users
  can('read', 'Article', { published: true });
  can('create', 'Article');
  can('update', 'Article', { authorId: user.id });
  can('delete', 'Article', { authorId: user.id });

  // Users can manage their own profile
  can('read', 'User', { id: user.id });
  can('update', 'User', { id: user.id });

  // Users can read profiles of their organization members
  if (user.organizationId) {
    can('read', 'User', { organizationId: user.organizationId });
  }

  // Premium users have additional capabilities
  if (user.subscription === 'premium') {
    can('export', 'Article');
    can('read', 'Analytics');
  }

  // Managers can manage their team members
  if (user.role === 'manager') {
    can('read', 'User', { managerId: user.id });
    can('update', 'User', { managerId: user.id });
    can('approve', 'Article', { department: user.department });
  }

  // Admins have full access
  if (user.role === 'admin') {
    can('manage', 'all');
  } else {
    // Explicit denials (override previous grants)
    cannot('delete', 'User');
    cannot('access', 'AdminPanel');
  }

  return build();
}

// Middleware to check authorization
function authorize(action, subject) {
  return async (req, res, next) => {
    const ability = defineAbilitiesFor(req.user);

    // For resource-specific checks, load the resource first
    let resource = subject;
    if (typeof subject === 'string' && req.params.id) {
      // Load resource from database
      const Model = db[subject.toLowerCase() + 's'];
      resource = await Model.findById(req.params.id);

      if (!resource) {
        return res.status(404).json({ error: `${subject} not found` });
      }
    }

    // Check if user can perform action on resource
    if (ability.cannot(action, resource)) {
      return res.status(403).json({
        error: 'Forbidden',
        message: `You cannot ${action} this ${subject}`
      });
    }

    // Attach ability to request for use in handler
    req.ability = ability;
    req.resource = resource;
    next();
  };
}

// Apply ABAC to API endpoints
router.get('/api/users/:id', 
  authenticateJWT,
  authorize('read', 'User'),
  async (req, res) => {
    res.json(req.resource); // Resource loaded by authorize middleware
  }
);

router.put('/api/articles/:id', 
  authenticateJWT,
  authorize('update', 'Article'),
  async (req, res) => {
    // Update the article
    await req.resource.update(req.body);
    res.json(req.resource);
  }
);

router.get('/api/articles',
  authenticateJWT,
  async (req, res) => {
    const ability = defineAbilitiesFor(req.user);

    // Build database query based on user's permissions
    const query = {};

    // Regular users can only see published articles
    if (ability.cannot('read', 'Article', { published: false })) {
      query.published = true;
    }

    // Non-admin users can only see their own drafts
    if (!req.user || req.user.role !== 'admin') {
      query.$or = [
        { published: true },
        { authorId: req.user?.id }
      ];
    }

    const articles = await db.articles.find(query);

    // Filter results based on field-level permissions
    const sanitized = articles.map(article => {
      const obj = article.toObject();

      // Remove sensitive fields if user can't read them
      if (ability.cannot('read', article, 'authorEmail')) {
        delete obj.authorEmail;
      }

      return obj;
    });

    res.json(sanitized);
  }
);

// Audit logging for authorization decisions
function logAuthorizationDecision(user, action, resource, granted) {
  db.auditLog.create({
    timestamp: new Date(),
    userId: user?.id,
    action,
    resourceType: resource.constructor.name,
    resourceId: resource.id,
    granted,
    userAttributes: {
      role: user?.role,
      subscription: user?.subscription,
      organizationId: user?.organizationId
    }
  });
}

module.exports = router;
